public class ArrayDemoMulti {
    public static void main(String[] args) {
        int[][][] cube = new int[2][2][2];
        int value = 1;
        for(int i = 0; i < 2; i++) {
            for(int j = 0; j < 2; j++) {
                for(int k = 0; k < 2; k++) {
                    cube[i][j][k] = value++;
                    System.out.println("cube[" + i + "][" + j + "][" + k + "] = " + cube[i][j][k]);
                }
            }
        }
    }
}

